mapper.select:
SELECT s.*, s.gallery_images as gallery_images_str
FROM `shop` s


        AND s.top_recommend = #{param.searchField1}


        AND s.receipt_status = #{param.searchField2}


        AND s.qualification_cert = #{param.searchField3}


        AND s.shop_status = #{param.searchField4}


        AND s.status = #{param.searchIntStatus}


        AND EXISTS (
        SELECT 1 FROM business_circle_shop bus
        WHERE bus.shop_id = s.id AND bus.circle_id = #{param.searchId}
        )


        AND EXISTS (
        SELECT 1 FROM shop_industry_category sic
        WHERE sic.shop_id = s.id AND sic.industry_category_id = #{param.searchField5}
        )


        AND s.name LIKE CONCAT('%', #{param.keyword}, '%')


        AND s.create_time >= #{param.startTime}


        AND s.create_time <= #{param.endTime}

    AND delete_time IS NULL

ORDER BY s.recommend_order DESC, s.id DESC

SELECT id
FROM shop
WHERE name = #{name}

    AND id != #{id}

AND delete_time IS NULL

SELECT bcs.circle_id AS circleId, bcs.shop_id AS shopId, s.name AS shopName FROM business_circle_shop bcs left join shop s on bcs.shop_id = s.id WHERE bcs.circle_id IN
#{item}
AND s.delete_time IS NULL

mapper.delete:
UPDATE `shop` SET delete_time = NOW() WHERE id IN
#{item}
AND delete_time IS NULL
